      for (let px = 1; px < cssW - 1; px++) {
        const o = owners[py * cssW + px];
        if (
          owners[(py - 1) * cssW + px] !== o ||
          owners[(py + 1) * cssW + px] !== o ||
          owners[py * cssW + (px - 1)] !== o ||
          owners[py * cssW + (px + 1)] !== o
